  // Your code here
}

solution.code:
function countBy(arr, fn) {
  const result = {};
  arr.forEach(item => {
    const key = fn(item);
    result[key] = (result[key] || 0) + 1;
  });
  return result;
}
const counts = countBy([1, 2, 3, 4, 5], n => n % 2 === 0 ? "even" : "odd");
console.log(Object.entries(counts).map(([k, v]) => k + ":" + v).join(","));

