  constructor() {
    this.forward = new Map();
    this.reverse = new Map();
  }
  set(key, value) {
    if (this.forward.has(key)) this.reverse.delete(this.forward.get(key));
    if (this.reverse.has(value)) this.forward.delete(this.reverse.get(value));
    this.forward.set(key, value);
    this.reverse.set(value, key);
  }
  getByKey(key) {
    return this.forward.get(key);
  }
  getByValue(value) {
    return this.reverse.get(value);
  }
}

