function validate(value) {
  const errors = [];
  const chain = {
    isString() {
      if (typeof value !== 'string') errors.push('Value must be a string');
      return chain;
    },
    minLength(n) {
      if (typeof value === 'string' && value.length < n) errors.push('Minimum length is ' + n);
      return chain;
    },
    matches(regex) {
      if (typeof value === 'string' && !regex.test(value)) errors.push('Does not match pattern');
      return chain;
    },
    result() {
      return { valid: errors.length === 0, errors };
    }
  };
  return chain;
}

