  return {
    [Symbol.asyncIterator]() {
      let current = start;
      return {
        next() {
          if (current <= end) {
            const value = current++;
            return new Promise(resolve => {
              setTimeout(() => resolve({ value, done: false }), 50);
            });
          }
          return Promise.resolve({ value: undefined, done: true });
        }
      };
    }
  };
}

