function kthLargest(nums, k) {
  const arr = nums.slice();
  const target = arr.length - k;
  function partition(l, r, pivotIdx) {
    const pivot = arr[pivotIdx];
    [arr[pivotIdx], arr[r]] = [arr[r], arr[pivotIdx]];
    let store = l;
    for (let i = l; i < r; i++) {
      if (arr[i] < pivot) {
        [arr[store], arr[i]] = [arr[i], arr[store]];
        store++;
      }
    }
    [arr[store], arr[r]] = [arr[r], arr[store]];
    return store;
  }
  function select(l, r) {
    if (l === r) return arr[l];
    const pivotIdx = Math.floor((l + r) / 2);
    const idx = partition(l, r, pivotIdx);
    if (idx === target) return arr[idx];
    if (idx < target) return select(idx + 1, r);
    return select(l, idx - 1);
  }
  return select(0, arr.length - 1);
}
console.log(kthLargest([3, 2, 1, 5, 6, 4], 2));

