solution.code:
function dijkstra(graph, start) {
  const dist = {};
  const visited = new Set();
  for (const node in graph) dist[node] = Infinity;
  dist[start] = 0;

  while (true) {
    let curr = null;
    let best = Infinity;
    for (const node in dist) {
      if (!visited.has(node) && dist[node] < best) {
        best = dist[node];
        curr = node;
      }
    }
    if (curr === null) break;
    visited.add(curr);
    for (const [next, w] of graph[curr]) {
      if (dist[curr] + w < dist[next]) dist[next] = dist[curr] + w;
    }
  }
  return dist;
}
const graph = {
  A: [["B", 1], ["C", 4]],
  B: [["C", 2], ["D", 5]],
  C: [["D", 1]],
  D: []
};
console.log(dijkstra(graph, "A").D);

