function longestPalindrome(s) {
  let bestStart = 0;
  let bestLen = 1;
  function expand(l, r) {
    while (l >= 0 && r < s.length && s[l] === s[r]) {
      l--;
      r++;
    }
    return [l + 1, r - l - 1];
  }
  for (let i = 0; i < s.length; i++) {
    const [s1, len1] = expand(i, i);
    if (len1 > bestLen) {
      bestStart = s1;
      bestLen = len1;
    }
    const [s2, len2] = expand(i, i + 1);
    if (len2 > bestLen) {
      bestStart = s2;
      bestLen = len2;
    }
  }
  return s.slice(bestStart, bestStart + bestLen);
}
