function mergeKSorted(arrays) {
  const heap = [];
  function push(node) {
    heap.push(node);
    let i = heap.length - 1;
    while (i > 0) {
      const p = Math.floor((i - 1) / 2);
      if (heap[p].val <= heap[i].val) break;
      [heap[p], heap[i]] = [heap[i], heap[p]];
      i = p;
    }
  }
  function pop() {
    if (heap.length === 0) return null;
    const min = heap[0];
    const last = heap.pop();
    if (heap.length > 0) {
      heap[0] = last;
      let i = 0;
      while (true) {
        let smallest = i;
        const l = i * 2 + 1;
        const r = i * 2 + 2;
        if (l < heap.length && heap[l].val < heap[smallest].val) smallest = l;
        if (r < heap.length && heap[r].val < heap[smallest].val) smallest = r;
        if (smallest === i) break;
        [heap[i], heap[smallest]] = [heap[smallest], heap[i]];
        i = smallest;
      }
    }
    return min;
  }
  for (let i = 0; i < arrays.length; i++) {
    if (arrays[i].length > 0) push({ val: arrays[i][0], arr: i, idx: 0 });
  }
  const res = [];
  while (heap.length > 0) {
    const node = pop();
    res.push(node.val);
    const nextIdx = node.idx + 1;
    if (nextIdx < arrays[node.arr].length) {
      push({ val: arrays[node.arr][nextIdx], arr: node.arr, idx: nextIdx });
    }
  }
  return res;
}
