  const res = [];
  while (heap.length > 0) {
    const node = pop();
    res.push(node.val);
    const nextIdx = node.idx + 1;
    if (nextIdx < arrays[node.arr].length) {
      push({ val: arrays[node.arr][nextIdx], arr: node.arr, idx: nextIdx });
    }
  }
  return res;
}

