function leastInterval(tasks, n) {
  const freq = new Map();
  for (const t of tasks) freq.set(t, (freq.get(t) || 0) + 1);
  let max = 0;
  let countMax = 0;
  for (const val of freq.values()) {
    if (val > max) {
      max = val;
      countMax = 1;
    } else if (val === max) {
      countMax++;
    }
  }
  const slots = (max - 1) * (n + 1) + countMax;
  return Math.max(slots, tasks.length);
}
