solution.code:
function minWindow(s, t) {
  const need = new Map();
  for (const ch of t) need.set(ch, (need.get(ch) || 0) + 1);
  const have = new Map();
  let formed = 0;
  const required = need.size;
  let l = 0;
  let best = [0, Infinity];
  for (let r = 0; r < s.length; r++) {
    const ch = s[r];
    have.set(ch, (have.get(ch) || 0) + 1);
    if (need.has(ch) && have.get(ch) === need.get(ch)) formed++;
    while (l <= r && formed === required) {
      if (r - l + 1 < best[1]) best = [l, r - l + 1];
      const leftCh = s[l++];
      have.set(leftCh, have.get(leftCh) - 1);
      if (need.has(leftCh) && have.get(leftCh) < need.get(leftCh)) formed--;
    }
  }
  if (best[1] === Infinity) return "";
  return s.slice(best[0], best[0] + best[1]);
}
