function decodeString(s) {
  const countStack = [];
  const strStack = [];
  let curr = "";
  let num = 0;
  for (const ch of s) {
    if (ch >= "0" && ch <= "9") {
      num = num * 10 + Number(ch);
    } else if (ch === "[") {
      countStack.push(num);
      strStack.push(curr);
      num = 0;
      curr = "";
    } else if (ch === "]") {
      const times = countStack.pop();
      const prev = strStack.pop();
      curr = prev + curr.repeat(times);
    } else {
      curr += ch;
    }
  }
  return curr;
}
